using System.Linq; using System.Data.Entity; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class InventoryOverviewPage:Page { public InventoryOverviewPage(){InitializeComponent(); tbWelcome.Text="Склад: "+AppConnect.CurrentUser.FullName; tbRole.Text="Роль: "+AppConnect.CurrentUser.UserRoles.RoleName; cmbSort.ItemsSource=new[]{"По названию","Остаток ↑","Остаток ↓"}; cmbSort.SelectedIndex=0; cmbCategory.ItemsSource=AppConnect.model01.Categories.ToList(); cmbCategory.DisplayMemberPath="CategoryName"; LoadProducts();} void LoadProducts(){var q=AppConnect.model01.Products.Include("Categories").Include("StockBalances").Where(x=>x.IsActive); if(cmbCategory.SelectedItem is Categories c) q=q.Where(x=>x.CategoryID==c.CategoryID); var t=txtSearch.Text.Trim().ToLower(); var list=q.ToList().Where(x=>t==""||x.ProductName.ToLower().Contains(t)||x.Sku.ToLower().Contains(t)); lvProducts.ItemsSource=list.Select(x=>new{ProductName=x.ProductName, Price=x.SalePrice, QuantityInStock=x.QuantityInStock, Description=x.Sku+" — "+x.Description, SourceProduct=x});} private void txtSearch_TextChanged(object s,TextChangedEventArgs e){LoadProducts();} private void cmbSort_SelectionChanged(object s,SelectionChangedEventArgs e){LoadProducts();} private void cmbCategory_SelectionChanged(object s,SelectionChangedEventArgs e){LoadProducts();} private void btnAddToCart_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new ShipmentsPage());} private void btnDetails_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new StockItemDetailsPage((Products)((Button)s).Tag));} private void btnCart_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new StockBalancesPage());} private void btnProfile_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new EmployeeProfilePage());} private void btnAdmin_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new WarehouseProductsPage());} private void btnOrders_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new ShipmentsPage());} private void btnManageUsers_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new AdminUsersPage());} private void btnExit_Click(object s,RoutedEventArgs e){AppConnect.CurrentUser=null; AppFrame.frmMain.Navigate(new LoginPage());} }
}
